const input = $input.first().json;
const body = input.body || input;

const business_id = body.business_id || '';
const user_id = body.user_id || '';
const plan = (body.plan || '').toLowerCase();
const product_images = body.product_images || [];
const brand_dna = body.brand_dna || null;

const errors = [];
if (!business_id) errors.push('business_id is required');
if (!user_id) errors.push('user_id is required');
if (!['starter', 'growth', 'agency'].includes(plan)) errors.push('plan must be starter, growth, or agency');
if (!Array.isArray(product_images) || product_images.length === 0) errors.push('product_images must be a non-empty array of URLs');

if (errors.length > 0) {
  throw new Error(JSON.stringify({ status: 400, errors }));
}

return [{ json: { business_id, user_id, plan, product_images, brand_dna, image_count: product_images.length } }];

const input = $('Validate Input').first().json;
const brandDna = $('Fetch Brand DNA').first().json || {};
const marketingTrends = $('Fetch Marketing Trends').first().json || {};
const igTrends = $('Fetch Instagram Trends').first().json || {};

const trendSnippets = [
  ...(marketingTrends.organic_results || []).slice(0, 5).map(r => r.snippet || r.title || ''),
  ...(igTrends.organic_results || []).slice(0, 5).map(r => r.snippet || r.title || '')
].filter(Boolean).join('\n');

const brand = [
  brandDna.brand_tone ? `Brand tone: ${brandDna.brand_tone}` : '',
  brandDna.target_audience ? `Target audience: ${brandDna.target_audience}` : '',
  brandDna.industry ? `Industry: ${brandDna.industry}` : '',
  brandDna.usp ? `USP: ${brandDna.usp}` : '',
  brandDna.brand_values ? `Values: ${brandDna.brand_values}` : '',
  brandDna.business_name ? `Business: ${brandDna.business_name}` : ''
].filter(Boolean).join('\n');

return [{ json: {
  ...input,
  brand_context: brand,
  trend_context: trendSnippets,
  industry: brandDna.industry || 'business',
  business_name: brandDna.business_name || '',
  brand_tone: brandDna.brand_tone || 'professional',
  target_audience: brandDna.target_audience || 'small business owners',
  timezone: brandDna.timezone || 'UTC'
} }];

