const ctx = $input.first().json;
const schedule = ctx.posting_schedule || [];
const platforms = ['instagram', 'tiktok', 'facebook'];
if (ctx.plan === 'agency') platforms.push('linkedin');

// Build content library rows
const rows = [];
for (const entry of schedule.slice(0, 60)) {
  const platform = entry.platform || 'instagram';
  const captions = ctx.captions || {};
  const platCaptions = captions[platform] || {};

  rows.push({
    user_id: ctx.user_id,
    business_id: ctx.business_id,
    content_type: entry.content_type || 'image',
    file_url: entry.content_type === 'sora_ad' ? ctx.sora_video_url
      : entry.content_type === 'kling_video' ? ctx.kling_video_url
      : ctx.generated_url,
    caption: platCaptions.caption || '',
    hashtags: (platCaptions.hashtags || []).join(' '),
    platform,
    content_score: ctx.content_score || 0,
    score_breakdown: JSON.stringify(ctx.score_breakdown || {}),
    status: 'scheduled',
    scheduled_at: entry.date + 'T' + (entry.time || '12:00') + ':00Z',
    prompt_type: entry.prompt_type || ctx.prompt_type || 'studio'
  });
}

return [{ json: { ...ctx, content_rows: rows, content_count: rows.length } }];

